// Payload: { name, role, group, phone, email, pin, rd, address, photo (base64 dataURL),
//             emergency_name, emergency_phone, assigned_id, level, status='идэвхтэй',
//             joined_at, requested_at }
const body = $input.first().json.body || $input.first().json || {};

// Phone-ийг норморчилох (зөвхөн тоо)
const phoneNorm = String(body.phone || '').replace(/\D/g, '');

// Filename — нэр + утас. "Болд_Энх_99112233.jpg".
const nameClean = String(body.name || 'unknown').replace(/[^\p{L}\d]+/gu, '_').slice(0, 40);
const filename = `${nameClean}_${phoneNorm || 'no-phone'}.jpg`;

// Photo нь dataURL хэлбэртэй: 'data:image/jpeg;base64,<base64>'
let photoBase64 = '';
let hasPhoto = false;
if (body.photo && body.photo.startsWith('data:image/')) {
  const m = body.photo.match(/^data:image\/[\w+]+;base64,(.+)$/);
  if (m) {
    photoBase64 = m[1];
    hasPhoto = true;
  }
}

// Request ID — track-д хэрэглэгдэнэ
const requestId = 'REQ_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);

return [{
  json: {
    request_id: requestId,
    filename,
    has_photo: hasPhoto,
    photo_base64: photoBase64,
    // Sheet-д бичигдэх талбарууд — App тал ID + level автомат тогтоосон
    'ID': String(body.assigned_id || '').toUpperCase(),
    'Овог нэр': body.name || '',
    'Албан тушаал': body.role || '',
    'Бүлэг': body.group || '',
    'Зэрэглэл': Number(body.level || 40),
    'Утас': body.phone || '',
    'И-мэйл': body.email || '',
    'PIN': body.pin || '',
    'РД': body.rd || '',
    'Гэрийн хаяг': body.address || '',
    'Яаралтай үед холбоо барих хүн': (body.emergency_relation ? (body.emergency_relation + ' — ') : '') + (body.emergency_name || ''),
    'Утас 2': body.emergency_phone || '',
    'Зургийн URL': '',
    'Төлөв': body.status || 'идэвхтэй',
    'Хүсэлтийн ID': requestId,
    'Хүсэлт өгсөн': body.requested_at || new Date().toISOString(),
    'Орсон огноо': body.joined_at || new Date().toISOString().slice(0, 10),
  },
  binary: hasPhoto ? {
    photo: {
      data: photoBase64,
      mimeType: 'image/jpeg',
      fileName: filename,
    }
  } : {},
}];

// Drive upload-аас гарсан file ID-г Sheet-д бичих form-руу нэгтгэх.
// Webhook view-ыг шууд хуваалцах боломжтой URL болгож хувиргана.
const orig = $('Parse payload + filename').item.json;
const driveFile = $input.first().json;
const fileId = driveFile.id;
const publicUrl = fileId ? `https://drive.google.com/uc?id=${fileId}` : '';
return [{ json: { ...orig, 'Зургийн URL': publicUrl, drive_file_id: fileId } }];
